{"code": "import json
import re
from datetime import datetime

# Load business data from file
business_file = var_functions.query_db:6
with open(business_file, 'r') as f:
    business_data = json.load(f)

# Load review data
review_data = var_functions.query_db:8

# Parse time to check if it's after 6:00 PM
def parse_closing_time(time_str):
    """Parse closing time string and return minutes since midnight, or None if invalid."""
    if not time_str or time_str == "Closed":
        return None

    # Handle "Open 24 hours"
    if "24 hours" in time_str:
        return 24 * 60  # Midnight next day (treated as late)

    # Clean up the string
    time_str = time_str.strip().replace('\u2013', '').replace('\u2014', '')

    # Extract time part (remove any day names if present)
    time_match = re.search(r'(\d{1,2})(?::(\d{2}))?\s*(AM|PM|am|pm)?', time_str)
    if not time_match:
        return None

    hour = int(time_match.group(1))
    minute = int(time_match.group(2)) if time_match.group(2) else 0
    ampm = time_match.group(3)

    # Convert to 24-hour format
    if ampm:
        ampm = ampm.upper()
        if ampm == 'PM' and hour != 12:
            hour += 12
        elif ampm == 'AM' and hour == 12:
            hour = 0
    else:
        # If no AM/PM specified, assume PM if hour < 6 (e.g., "9" means 9PM?)
        # But let's be conservative and only count if explicit
        return None

    return hour * 60 + minute

def is_after_6pm(time_str):
    """Check if closing time is after 6:00 PM (18:00)."""
    minutes = parse_closing_time(time_str)
    if minutes is None:
        return False

    # 6:00 PM = 18:00 = 1080 minutes
    return minutes > 1080

# Check if business is open after 6PM on any weekday
def check_weekday_hours(hours_str):
    """Check if business is open after 6PM on any weekday."""
    if not hours_str or hours_str == 'None':
        return False

    try:
        # The hours string is a string representation of a Python list
        hours_list = eval(hours_str)

        weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

        for day_entry in hours_list:
            if len(day_entry) >= 2:
                day = day_entry[0]
                hours = day_entry[1]

                if day in weekdays:
                    # Parse the hours string to get closing time
                    if 'Open 24 hours' in hours:
                        return True

                    # Split by dash/endash to get open and close times
                    for sep in ['\u2013', '\u2014', '-']:
                        if sep in hours:
                            times = hours.split(sep)
                            if len(times) >= 2:
                                close_time = times[1].strip()
                                if is_after_6pm(close_time):
                                    return True
                            break
    except:
        # If parsing fails, skip this business
        pass

    return False

# Filter businesses that are open after 6PM on at least one weekday
eligible_businesses = []
for business in business_data:
    if check_weekday_hours(business['hours']):
        eligible_businesses.append(business)

print(f"Number of businesses open after 6PM on weekdays: {len(eligible_businesses)}")
print("__RESULT__:")
print(json.dumps(eligible_businesses[:3]))  # Print first 3 as preview"}

