        # Safely evaluate the hours string (it's a string representation of a list)
        if not (hours_str.startswith('[') and hours_str.endswith(']')):
            return False

        # Use json.loads instead of eval for safety
        hours_list = json.loads(hours_str.replace("'", '"'))

        weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

        for day_entry in hours_list:
            if len(day_entry) >= 2:
                day = day_entry[0]
                hours = day_entry[1]

                if day in weekdays:
