                        if sep in hours:
                            times = hours.split(sep)
                            if len(times) >= 2:
                                close_time = times[1].strip()
                                if is_after_6pm(close_time):
                                    return True
                            break
    except:
        # If parsing fails, skip this business
        pass

    return False

