businesses_with_ratings = []
for business in eligible_businesses:
    gmap_id = business['gmap_id']
    if gmap_id in review_lookup:
        businesses_with_ratings.append({
            'name': business['name'],
            'gmap_id': gmap_id,
            'hours': business['hours'],
            'avg_rating': review_lookup[gmap_id]
        })

# Sort by average rating (descending) and get top 5
top_5_businesses = sorted(businesses_with_ratings, key=lambda x: x['avg_rating'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps(top_5_businesses, indent=2))"}

