{"code": "import json
import re

# Get stored data
storage = locals()
business_file = storage.get('var_functions.query_db:6')
review_data = storage.get('var_functions.query_db:8')

# Load business data
with open(business_file, 'r') as f:
    all_businesses = json.load(f)

# Process data
def parse_time(t):
    if not t or t == 'Closed':
        return None
    if '24 hours' in t:
        return 24 * 60
    m = re.search(r'(\d{1,2})(?::(\d{2}))?\s*(AM|PM|am|pm)?', t)
    if not m:
        return None
    h = int(m.group(1))
    minute = int(m.group(2)) if m.group(2) else 0
    ampm = m.group(3)
    if ampm:
        ampm = ampm.upper()
        if ampm == 'PM' and h != 12:
            h += 12
        elif ampm == 'AM' and h == 12:
            h = 0
    else:
        return None
    return h * 60 + minute

def after_6pm(t):
    minutes = parse_time(t)
    return minutes is not None and minutes > 1080

def check_hours(hours_str):
    if not hours_str or hours_str == 'None':
        return False
    try:
        hours_list = json.loads(hours_str.replace("'", '"'))
        weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']
        for entry in hours_list:
            if len(entry) >= 2:
                day, hours = entry[0], entry[1]
                if day in weekdays:
                    if 'Open 24 hours' in hours:
                        return True
                    for sep in ['\u2013', '\u2014', '-']:
                        if sep in hours:
                            parts = hours.split(sep)
                            if len(parts) >= 2:
                                if after_6pm(parts[1].strip()):
                                    return True
                            break
    except:
        return False
    return False

# Filter businesses
eligible = [b for b in all_businesses if check_hours(b.get('hours', ''))]

# Join with ratings
review_dict = {r['gmap_id']: float(r['avg_rating']) for r in review_data}
result = []
for b in eligible:
    gid = b['gmap_id']
    if gid in review_dict:
        result.append({
            'name': b['name'],
            'gmap_id': gid,
            'hours': b['hours'],
            'avg_rating': review_dict[gid]
        })

# Get top 5 by rating
top5 = sorted(result, key=lambda x: x['avg_rating'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps(top5, indent=2))"}

